+#[async_trait]
+impl Provider for AzureOpenAIProvider {
+    fn name(&self) -> &'static str {
+        "azure"
+    }
+
+    fn api(&self) -> &'static str {
+        "azure-openai"
+    }
+
+    async fn stream(
+        &self,
+        context: &Context,
+        options: &StreamOptions,
+    ) -> Result<Pin<Box<dyn Stream<Item = Result<StreamEvent>> + Send>>> {
+        let api_key = options
+            .api_key
+            .clone()
+            .or_else(|| std::env::var("AZURE_OPENAI_API_KEY").ok())
+            .ok_or_else(|| Error::config("Missing Azure OpenAI API key"))?;
+
+        let request_body = self.build_request(context, options);
+
+        // Build request with Azure-specific headers
+        let mut request = self
+            .client
+            .post(self.endpoint_url())
+            .header("Content-Type", "application/json")
+            .header("api-key", &api_key); // Azure uses api-key header, not Authorization
+
+        for (key, value) in &options.headers {
+            request = request.header(key, value);
+        }
+
+        let request = request.json(&request_body);
+
+        // Create event source for SSE streaming
+        let event_source = EventSource::new(request).map_err(|e| Error::api(e.to_string()))?;
+
+        // Create stream state
+        let model = self.deployment.clone();
+        let api = self.api().to_string();
+        let provider = self.name().to_string();
+
+        let stream = stream::unfold(
+            StreamState::new(event_source, model, api, provider),
+            |mut state| async move {
+                loop {
+                    match state.event_source.next().await {
+                        Some(Ok(Event::Open)) => {}
+                        Some(Ok(Event::Message(msg))) => {
+                            // Azure also sends "[DONE]" as final message
+                            if msg.data == "[DONE]" {
+                                let reason = state.partial.stop_reason;
+                                return Some((
+                                    Ok(StreamEvent::Done {
+                                        reason,
+                                        message: state.partial.clone(),
+                                    }),
+                                    state,
+                                ));
+                            }
+
+                            match state.process_event(&msg.data) {
+                                Ok(Some(event)) => return Some((Ok(event), state)),
+                                Ok(None) => {}
+                                Err(e) => return Some((Err(e), state)),
+                            }
+                        }
+                        Some(Err(e)) => {
+                            let err = Error::api(format!("SSE error: {e}"));
+                            return Some((Err(err), state));
+                        }
+                        None => return None,
+                    }
+                }
+            },
+        );
+
+        Ok(Box::pin(stream))
+    }
+}
